-// ---------------------------------------------------------------------------
-// Integration result
-// ---------------------------------------------------------------------------
-
-/// Result of a single tool integration attempt.
-#[derive(Debug, Clone, Serialize)]
-pub struct IntegrationResult {
-    /// Which tool.
-    pub tool: AiTool,
-    /// Outcome status.
-    pub status: IntegrationStatus,
